const ICP_LOCATIONS = ['bengaluru', 'mumbai', 'chennai', 'new delhi', 'delhi', 'gurgaon'];
const ICP_ROLES = ['hr manager', 'administration', 'admin', 'human resource', 'hr', 'dgm', 'executive - hr', 'manager - hr', 'manager - administration & hr'];
const ICP_INDUSTRIES = ['information technology', 'manufacturing', 'services', 'it', 'ites'];

let validLeads = [];

for (const item of $input.all()) {
  const lead = item.json;
  let score = 0;
  let reasons = [];

  // If the row is completely empty, skip it
  if (!lead['Name of the Company'] && !lead['161']) continue;

  const city = (lead['City'] || '').toString().toLowerCase();
  if (ICP_LOCATIONS.some(loc => city.includes(loc))) {
    score += 20;
    reasons.push('Location');
  }

  const role = (lead['Job Title'] || '').toString().toLowerCase();
  const dept = (lead['Dept'] || '').toString().toLowerCase();
  if (ICP_ROLES.some(r => role.includes(r) || dept.includes(r))) {
    score += 25;
    reasons.push('Role');
  }

  const industry = (lead['Industry Segment'] || '').toString().toLowerCase();
  if (ICP_INDUSTRIES.some(ind => industry.includes(ind))) {
    score += 30;
    reasons.push('Industry');
  }

  let tag = 'Cold';
  if (score >= 75) tag = 'Hot';
  else if (score >= 40) tag = 'Warm';

  // Only taking max 100 rows for demo so it doesn\'t crash google sheets free tier
  if(validLeads.length < 100) {
      validLeads.push({
        json: {
          'Company Name': lead['Name of the Company'] || lead['161'] || '',
          'Contact Name': lead['Name'] || lead['Unnamed: 1'] || '',
          'Job Title': lead['Job Title'] || lead['Unnamed: 2'] || '',
          'Dept': lead['Dept'] || lead['Unnamed: 3'] || '',
          'Email': lead['Email'] || lead['Unnamed: 4'] || '',
          'City': lead['City'] || lead['Unnamed: 9'] || '',
          'Industry': lead['Industry Segment'] || lead['Unnamed: 16'] || '',
          'ICP_Score': score,
          'ICP_Tag': tag,
          'Match_Reasons': reasons.join(', ') || 'No match'
        }
      });
  }
}

return validLeads;
